import './HighTechOffice.css'

import HighTechGallery1 from '../../assets/public/Офис Екатеринбург/8.jpg'
import HighTechGallery2 from '../../assets/public/Офис Екатеринбург/9.jpg'
import HighTechGallery3 from '../../assets/public/Офис Екатеринбург/2.jpg'
import HighTechGallery4 from '../../assets/public/Офис Екатеринбург/7.jpg'
import HighTechGallery5 from '../../assets/public/Офис Екатеринбург/ОБЛОЖКА.jpg'
import arrow from '../../assets/icons/arrowhead-up.png'
import InfiniteImageSlider from '../../components/InfiniteImageSlider/InfiniteImageSlider'
import { useState } from 'react'
import { useTranslation } from 'react-i18next'

function HighTechOffice() {
    const { t } = useTranslation();
    const images = [HighTechGallery1,
                    HighTechGallery2,
                    HighTechGallery3,
                    HighTechGallery4,
                    HighTechGallery5]
    const [sliderStartIndex, setSliderStartIndex] = useState(0)
    const [sliderVisible, setSliderVisible] = useState(false)

    const handleMonochromeImageClick = (index) => {
        setSliderStartIndex(index)
        setSliderVisible(true)
    }

    const closeSlider = () => {
        setSliderVisible(false)
    }

    return ( 
    <section id="Hightech">
        <div className="hightech-block hightech-block-title">
            <div className="hightech-title">
                <span className='hightech-title-bold'>{t("High-tech office")}</span>
                <span>{t("Yekaterinburg")}</span>
                <span>2020</span>
            </div>
            <p className="hightech-description">
                {t("hightech-description")}
            </p>
        </div>
        <div className="hightech-block hightech-wide">
            <img src={HighTechGallery1} className='slider-item-img' alt="" onClick={()=>{handleMonochromeImageClick(0)}} loading='lazy'/>
        </div>
        <div className="hightech-block hightech-triple">
            <img src={HighTechGallery2} className='slider-item-img' alt="" onClick={()=>{handleMonochromeImageClick(1)}} loading='lazy'/>
            <img src={HighTechGallery3} className='slider-item-img' alt="" onClick={()=>{handleMonochromeImageClick(2)}} loading='lazy'/>
            <img src={HighTechGallery4} className='slider-item-img' alt="" onClick={()=>{handleMonochromeImageClick(3)}} loading='lazy'/>
        </div>
        <div className="hightech-block hightech-wide">
            <img src={HighTechGallery5} className='slider-item-img' alt="" onClick={()=>{handleMonochromeImageClick(4)}} loading='lazy'/>
        </div>
        <a href="#Hightech">
            <button className="home-projects-anchor-btn" ><img src={arrow} alt="" /></button>
        </a>
        {sliderVisible ? <InfiniteImageSlider content={images} startIndex={sliderStartIndex} closeFunction={closeSlider}/> : <></>}
    </section> );
}

export default HighTechOffice;