import { NavLink } from 'react-router-dom'
import { useTranslation } from 'react-i18next'

import logoGreen from '../../assets/design/logo-green.png'
import LanguageSwitcher from '../Header/LanguageSwitcher/LanguageSwitcher'

import './HeaderSimple.css'

function HeaderSimple(props){
    const { t } = useTranslation();

    return(
        <div className="header-container-simple">
            <header className="header-simple" >
                <nav className='header-simple-nav header-nav'>
                    <NavLink to={'/'}>{t("home")}</NavLink>
                    <NavLink to={'/about'}>{t("about")}</NavLink>
                    <NavLink to={'/projects'}>{t("projects")}</NavLink>
                    <NavLink to={'/contacts'}>{t("contacts")}</NavLink>
                </nav>
                <LanguageSwitcher/>
                <div className="header-simple-logo-container">
                    <span className="header-simple-sh">Sh</span>
                    <span className="header-simple-title">
                        interior <br/> design <br/> studio
                    </span>
                    <img className='header-simple-logo' src={logoGreen} alt="" width="83px" height="83px" draggable='false'/>
                </div>
                
            </header>

        </div>
    )
}

export default HeaderSimple