import './Private.css'
import { Link } from 'react-router-dom'
import { useTranslation } from 'react-i18next'
import fusion from '../../assets/private/fusion.jpeg'
import white from '../../assets/private/white-apartament.jpeg'
import loft from '../../assets/private/loft.jpeg'
import mono from '../../assets/private/monochrome.jpeg'

import PrivateCell from './PrivateCell/PrivateCell'

function Private(props){
    const { t } = useTranslation();
    return(
        <section id="Private">
            <div className="private-container">
                <div className="private-table">
                    <Link to='/fusion'><PrivateCell class={'fusion'} image={fusion} title={t("Fusion in Zamoskvorechye")} wide={false} /></Link>
                    <PrivateCell class={'white'} image={white} title={t("White Apartament")} wide={true}/>
                    <PrivateCell class={'loft'} image={loft} title={t("Loft in Georgia")} wide={true}/>
                    <Link to='/monochrome'><PrivateCell class={'mono'} image={mono} title={t("Monochrome minimalism")} wide={false}/></Link>
                </div>
            </div>
        </section>
    )
}

export default Private